var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그쪽은 어때? 사람 그림자라도 보여?","JPN":"そっちはどう？　人影でも見える？","ENG":"How about over there? Do you see even a single person?","TWN":"那邊怎麼樣？看到人影了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...제 눈에도 보이지 않사옵니다.","JPN":"……わたくしにも見えません。","ENG":"...I can't see anyone either.","TWN":"……我沒看到。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이렇게 아침 일찍 이곳에 와본 것은 처음이라...","JPN":"こんな朝早くにここに来たのは初めてなので……","ENG":"It is my first time coming here this early in the morning...","TWN":"我還是第一次這麼早來到這裡……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"힉-","JPN":"ひっ……","ENG":"Eek–","TWN":"咿—"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 그래?","JPN":"どうしたの？","ENG":"What is it?","TWN":"怎麼了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"저기에, 새까만 것이 툭 떨어졌사온데...","JPN":"あそこに、真っ黒なものが落ちたのですが……","ENG":"Something pitch-black just fell over there...","TWN":"那邊剛才有個黑色的東西掉下來……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이건... 나뭇가지네.","JPN":"これは……木の枝だね。","ENG":"This is... just a tree branch.","TWN":"這是……樹枝。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"나뭇가지?","JPN":"木の枝？","ENG":"A tree branch?","TWN":"樹枝？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그리고 절단면이 반듯해. 누가 일부러 자른 것처럼.","JPN":"切断面がきれいだ。まるで誰かがわざと切ったように。","ENG":"And the cut is clean. Like someone cut it on purpose.","TWN":"而且切口很整齊，看起來像被人刻意砍下來的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그렇다는 건...?","JPN":"ということは……？","ENG":"Which means...?","TWN":"那表示……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"죄송해요. 혹시 떨어진 가지에 맞으셨나요?","JPN":"すみません。もしかして落ちた枝に当たりました？","ENG":"I'm sorry. Did a falling branch hit you?","TWN":"不好意思，你們有被掉下來的樹枝砸到嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"왜 나무를 타고 있는 거야?","JPN":"なんで木登りなんてしてるわけ？","ENG":"Why are you climbing a tree?","TWN":"你為什麼會爬到樹上？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"전 아침이 되면 가지를 치러 이곳에 나오거든요.","JPN":"私は朝になるとここに剪定に来るんです。","ENG":"Every morning, I come out here to trim the branches.","TWN":"我每天早上都會來這裡修剪樹枝。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"가지를 치고 있었다고?","JPN":"剪定？","ENG":"You were trimming branches?","TWN":"修剪樹枝？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"어차피 하루가 지나면 다시 돌아올 텐데, 그런 짓에 무슨 의미가 있지?","JPN":"どうせ一日が過ぎたらまた元通りになるのに、剪定する意味があるの？","ENG":"They'll just grow back tomorrow anyway. What's the point of doing something like that?","TWN":"反正過一天又會長回來，做這種事有什麼意義？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"확인해보고 싶어서요.","JPN":"確認してみたくて。","ENG":"Because I wanted to see.","TWN":"因為我想確認。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"어떤 가지를 자르고 어떤 가지를 남겨야, 나무그늘 아래의 햇살이 가장 아름답게 반짝이는지를.","JPN":"どんな枝を切ってどんな枝を残せば、木漏れ日が一番綺麗に輝くのかを。","ENG":"Which branches I should cut and which I should leave for the sunlight beneath the tree to sparkle most beautifully.","TWN":"到底要剪掉哪些樹枝、留下哪些樹枝，才能讓樹蔭下的陽光閃耀得最美。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"허.","JPN":"は。","ENG":"Huh.","TWN":"呵。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"죽은 사람도 살려내는 이 대단한 낙원에서 무슨 음모를 꾸미나 했더니, 매일 그런 시시한 놀이나 하고 있었다고?","JPN":"死んだ人も蘇らせるこの立派な楽園で何を企んでいるのかと思ったら、毎日そんなくだらない遊びをしてたの？","ENG":"So in this grand paradise that can even bring the dead back to life, I wondered what kind of scheme you were plotting... and it turns out you've just been playing trivial games like that every day?","TWN":"我還以為你在這個連死人都能復活的了不起樂園裡策劃著什麼陰謀，結果每天只是做這種無聊事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"후후, 시시한가요?","JPN":"ふふ、くだらないですか？","ENG":"Haha, is it trivial?","TWN":"呵呵，很無聊嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그치만 저에게 나뭇가지를 자르는 건, 이제 일상인 걸요.","JPN":"ですが私にとって木の枝を切ることは、もはや日常なんです。","ENG":"But trimming branches has become part of my daily life now.","TWN":"不過對我來說，修剪樹枝已經是日常生活了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"가장 완벽한 정오의 햇살을 눈에 담는 건 간단한 일이 아니니까요.","JPN":"一番完璧な正午の日差しを目にすることは、そう簡単なことではないですから。","ENG":"Capturing the most perfect midday sunlight is not such a simple thing.","TWN":"因為要把最完美的正午陽光收入眼中，可不是一件簡單的事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...아우드라.","JPN":"……アウドラ。","ENG":"...Audra.","TWN":"……奧德拉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"이 낙원을 만든 것이 그대입니까?","JPN":"この楽園を作ったのは、あなたなのですか？","ENG":"Was it really you who created this Promised Land?","TWN":"這個樂園，是你創造的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"Yes.","TWN":"是。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제가 엘리시온으로 오기 전에 살았던 고향의 풍경을 본 따 만들었어요.","JPN":"私がエリシオンに来る前に住んでいた故郷の風景を真似て作りました。","ENG":"I modeled it after the scenery of my hometown, where I lived before coming to Elysion.","TWN":"我按照自己來到艾利森前，曾住過的故鄉景色打造的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"아발론 몰락 이후에 세워진, 아나필리스라는 나라였죠.","JPN":"アバロンが没落した後に建てられた、アナピリスという国でした。","ENG":"It was a country called Anapilis, founded after the fall of Avalon.","TWN":"那是阿瓦隆滅亡後建立的國家，叫阿納菲莉絲。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"아나필리스...?","JPN":"アナピリス……？","ENG":"Anapilis...?","TWN":"阿納菲莉絲……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"에클리시아, 거기가 어딘지 알고 있어?","JPN":"エクレシア、知ってるの？","ENG":"Ecclesia, do you know where that is?","TWN":"艾可露西亞，你知道那是哪裡嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"...그곳에 대한 이야긴, 잘은 모릅니다.","JPN":"……その国についての詳しいことは存じません。","ENG":"...I don't know much about that place.","TWN":"……我完全不知道那個地方的事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"다만 엘리시온에선... 아나필리스라는 이국에서 온 신앙인들을 이교도라며 핍박했었지요.","JPN":"ただエリシオンでは……アナピリスという異国から来た信者たちを、異教徒だと迫害したのです。","ENG":"But in Elysion... believers who came from a foreign land called Anapilis were persecuted as heretics.","TWN":"不過在艾利森……來自阿納菲莉絲的信徒被視為異教徒而遭受迫害。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그들은 정해진 운명을 피하기 위해, 수단과 방법을 가리지 않는다면서요.","JPN":"彼らは定められた運命から逃れるためなら、手段と方法を選ばないと聞いておりますが……","ENG":"They said those people would stop at nothing to escape the destiny set for them.","TWN":"聽說他們會不擇手段，只為了逃避既定的命運。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제 언니도 그랬어요.","JPN":"私のお姉ちゃんもそうでした。","ENG":"My sister was like that too.","TWN":"我姐姐也是如此。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제가 가진 운명을 바꾸기 위해 다른 많은 목숨을 바치려 했고... 결국 실패했죠.","JPN":"私の持つ運命を変えるためにたくさんの命を捧げようとして……結局失敗しました。","ENG":"She tried to sacrifice many lives to change the destiny I was born with... and in the end, she failed.","TWN":"她想改變我的命運，為此犧牲了許多生命……最後還是失敗了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그 실패의 대가는, 엘리시움 필하모닉이 연구하던 멘탈 프린팅 기술의 실험 제물이 되는 거였고요.","JPN":"失敗の代償は、エリシウムフィルハーモニーが研究していたメンタル・プリンティング技術の実験体になるというものでした。","ENG":"The price of that failure was becoming a test subject for the Mental Printing technology being researched by Elysium Philharmonic.","TWN":"失敗的代價，就是成為愛樂組織研究智力複印技術的實驗祭品。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래서인가?","JPN":"それでなの？","ENG":"Is that why?","TWN":"所以才會這樣嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"타기리온은 그때의 증오심 때문에 세계를 멸망시키는 괴물이 되기로 한 거야?","JPN":"タギリオンが世界を滅ぼす化け物になると決めたのは、その時の憎悪のせいなの？","ENG":"Did Thagirion decide to become a monster that destroys the world because of the hatred from back then?","TWN":"塔基里翁是因為那時的仇恨，才決定成為毀滅世界的怪物嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"차가운 실험관에 갇힌 언니를 보았을 때의 증오심은... 그런 괴물이 되기에 충분했어요.","JPN":"冷たい試験管に閉じ込められたお姉ちゃんを見た時の憎悪は……そんな化け物になるに足りるものでした。","ENG":"The hatred I felt when I saw my sister trapped inside that cold experiment chamber... was certainly enough to turn someone into such a monster.","TWN":"當我看到姐姐被關在冰冷的實驗艙裡時的恨意……確實足以讓人變成那樣的怪物。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"하지만 증오란 건, 마음을 태우며 타오르는 불꽃이었고...","JPN":"でも憎悪というものは、心を焦がし燃え上がる炎であって……","ENG":"But hatred is a flame that burns the heart as it blazes.","TWN":"但是仇恨就像燃燒心靈的火焰……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"제 마음은 그 강렬한 불꽃을 견딜 만큼 강하지 못했나 봐요.","JPN":"私の心はその強烈な炎に耐えられるほど強くはなかったようです。","ENG":"And it seems my heart was not strong enough to endure that fierce flame.","TWN":"而我的心，似乎沒有強大到能承受那樣的烈火。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그날, 사람의 피를 내 손에 묻혔어요. 그것도 아주 많은 피를요.","JPN":"あの日、自分の手を他人の血で染めました。大量の血で。","ENG":"That day, I stained my hands with human blood. A great deal of it.","TWN":"那一天，我的雙手沾滿人的鮮血。而且是很多很多的血。"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L48_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"활활 타오르던 마음은... 널브러진 주검들 앞에서 금세 잿더미가 되고 말았죠.","JPN":"激しく燃え上がっていた心は……倒れている死体を前にしてたちまち灰となりました。","ENG":"The heart that had been burning so fiercely... turned to ashes before the scattered corpses lying everywhere.","TWN":"原本熊熊燃燒的心……在那些橫倒的屍體面前，很快就化成灰燼。"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"복수 끝에 찾아온 건, 후회도 죄책감도 아닌... 끝없는 낭떠러지로 떨어지는 기분이었어요.","JPN":"復讐の果てに訪れたのは、後悔でも罪悪感でもなく……奈落の底に落ちるような気持ちでした。","ENG":"What came after my revenge was not regret or guilt... but the feeling of falling endlessly into a bottomless abyss.","TWN":"復仇後降臨的不是後悔，也不是罪惡感……而是一種墜入無盡深淵的感覺。"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언니 이름이 쓰여진 실험관 안에서 둥실둥실 떠다니고 있는 그것이, 내가 발을 딛고 있던 유일한 세상이란 걸 깨달아버렸거든요.","JPN":"お姉ちゃんの名前が書いてある試験管の中でぷかぷかと漂う「それ」が、私の唯一の世界だったということに気づいてしまったからです。","ENG":"Because I realized the only world I had left to stand on... was that thing floating inside the experiment chamber with my sister's name on it.","TWN":"因為我發現，在寫著姐姐名字的實驗艙裡漂浮著的東西，就是我腳下唯一的世界。"},"stage":{"bg":"HARMONY2_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L2_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"언니가 절 두고 떠나기 전에 그런 말을 했어요.","JPN":"お姉ちゃんは私をおいて去る前に言っていました。","ENG":"Before my sister left me behind, she told me something.","TWN":"姐姐離開我之前，曾對我說過。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"너는 마왕이 될 운명이고, 어떤 희생을 치러서라도 너를 그 운명에서 구하겠다고.","JPN":"私が魔王になる運命であり、どんな犠牲を払ってでも私をその運命から救うと。","ENG":"That I was destined to become a Demon Lord, and that she would save me from that destiny no matter what sacrifice it took.","TWN":"你注定會成為魔王。不管付出什麼代價，我都要把你從這個命運救出來。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그러려면 가장 먼저, 흰 서리꽃이란 것을 찾아야 해... 라고.","JPN":"そのためにはまず、白い霜の花というものを探さないといけない……と。","ENG":"And that to do so, she first had to find something called the white frost flower...","TWN":"為此，要先找到一種叫做白霜花的東西……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"하지만 언니는 성공하지 못했고, 그렇게 제 품에 돌아왔어요.","JPN":"ですがお姉ちゃんは失敗し、そうやって私のところに戻ってきました。","ENG":"But my sister didn't succeed, and she returned to me like that.","TWN":"但姐姐沒有成功，就那樣回到了我的懷裡。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"잿더미가 된 마음으로, 운명을 받아들이는 것 말고 선택할 수 있는 건... 하나 밖에 없었죠.","JPN":"灰となった心で、運命を受け入れる以外に選択できることは……一つしかありませんでした。","ENG":"With a heart reduced to ashes, there was only one thing left for me to choose... instead of accepting my fate.","TWN":"心已經化為灰燼的我，除了接受命運之外……只剩下一個選擇。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그날의 광경을...","JPN":"あの日の光景を……","ENG":"The sight from that day...","TWN":"那一天的景象……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신에게도 보여줄게요.","JPN":"あなたにも見せてあげましょう。","ENG":"I'll show it to you as well.","TWN":"我也會讓你看見。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐...?","JPN":"え……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"큭? 어느새 내 앞으로...?!","JPN":"くっ？　いつの間に私の前に……！？","ENG":"Kgh? When did you get right in front of me...?!","TWN":"咳？！什麼時候跑到我面前的……？！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"레아 님!","JPN":"レア様！","ENG":"Ms. Leah!","TWN":"蕾亞！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"그 여자가 손을 뻗자, 아득한 어둠이 눈앞을 덮쳐왔다.","JPN":"女が手を伸ばすと、果てしない暗闇が目の前を覆った。","ENG":"When she reached out her hand, a vast darkness suddenly swallowed my vision.","TWN":"當那個女人伸出手時，無盡的黑暗瞬間籠罩眼前。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"다시금 빛이 스며든 시야엔 참혹한 풍경에 둘러싸인 소녀가 있었고,","JPN":"再び光が差し込んだ視界には、残酷な風景に囲まれた少女がいて、","ENG":"When the light returned to my sight, a girl stood there, surrounded by a horrific scene.","TWN":"當光線再次回到視野時，一名少女站在慘不忍睹的景象中。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"그 소녀에게 무어라 말을 걸 새도 없이, 소녀는 자신이 가진 무기를 휘둘렀다.","JPN":"私が言葉をかける暇もなく、少女は自分が持っていた武器を振り回した。","ENG":"Before I could even speak to her, the girl swung the weapon she held.","TWN":"我還來不及對她說什麼，少女就揮下手中的武器。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"소녀는... 스스로를 반으로 갈랐다.","JPN":"少女は……自分自身を真っ二つに斬った。","ENG":"The girl... split herself in half.","TWN":"少女……把自己劈成了兩半。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"그러나 피는 흐르지 않는다.","JPN":"でも、血が流れることはない。","ENG":"But no blood flowed.","TWN":"然而沒有血流出來。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"의식도 멀쩡하다.","JPN":"意識もしっかりある。","ENG":"She remained conscious.","TWN":"意識也依然清醒。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"그런 부자연스러운 흐름 속에서, 소녀는 뒤늦게 자신의 곁에 누군가 있다는 것을 깨달았다.","JPN":"そのような不自然な流れの中で、少女はやっと自分のそばに誰かがいるということに気づいた。","ENG":"Amid that unnatural flow of events, the girl belatedly realized that someone was standing beside her.","TWN":"在這種不自然的情況下，少女這才察覺到身邊有人。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"갑자기 나타났다기 보단, 언제인가부터 그곳에 있었다.","JPN":"いきなり現れたというより、いつからかそこにいた。","ENG":"Rather than suddenly appearing, it felt as though they had always been there.","TWN":"與其說突然出現，不如說那個人似乎從某個時候起就一直在那裡。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"그 익숙한 시선은... 어쩌면 모든 것이 시작되기 전부터 소녀를 지켜봐 왔던 것일지도 모른다.","JPN":"そのなじみのある視線は……もしかしたらすべてが始まる前から少女を見守っていたのかもしれない。","ENG":"That familiar gaze... perhaps it had been watching over the girl since before everything began.","TWN":"那道熟悉的目光……或許在一切開始之前，就已經在注視著少女。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"역경의 끝에서, 삶을 포기하기로 한 거니?","JPN":"逆境の果てに、人生を諦めることにしたの？","ENG":"At the end of your hardship, have you decided to give up on life?","TWN":"在走到絕境之後，你決定放棄生命了嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"...모든 것엔 이유가 있어야 하는데, 저에겐 그 이유가 없어요.","JPN":"……すべてには理由が必要なのに、私にはその理由がありません。","ENG":"...Everything should have a reason. But I have no such reason.","TWN":"……所有事情都應該有理由，但我卻沒有。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"살아있으면 더 많은 사람들을 해칠 뿐이지만, 여기서 멈춘다면 앞으로 겪게 될 모든 아픔도... 여기서 끝나겠죠.","JPN":"生きていればもっと多くの人を殺すだけですけど、ここで止まっておけばこれから経験するはずのすべての苦痛も……ここで終わるでしょう。","ENG":"If I keep living, I will only harm more people. But if I stop here, then all the pain I would face in the future... will end here as well.","TWN":"如果我繼續活下去，只會傷害更多人。但如果在這裡停下來，那未來所有的痛苦……也會在這裡結束吧。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"정말로 그럴까?","JPN":"本当にそうかな？","ENG":"Will it really?","TWN":"真的會是那樣嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"이 그림 속 사람은... 누구죠?","JPN":"この絵の中の人は……誰ですか？","ENG":"The person in that picture... who is it?","TWN":"這幅畫裡的人……是誰？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"이건 너야. 정확히는 다른 세계의 너지.","JPN":"これはあなただよ。正確には、別の世界のあなた。","ENG":"That is you. More precisely, you from another world.","TWN":"那是你。更準確地說，是另一個世界的你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"다른 세계의... 나?","JPN":"別の世界の……私？","ENG":"Me... from another world?","TWN":"另一個世界的……我？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"아우드라.","JPN":"アウドラ。","ENG":"Audra.","TWN":"奧德拉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"넌 네가 살아온 세계를 한 그루 나무라고 여겼지만, 사실 그건 한 줄기 나뭇가지에 지나지 않아.","JPN":"あなたは自分が住んでいた世界を1本の木と思っていたけれど、実はそれは1本の枝に過ぎないの。","ENG":"You believed the world you lived in was a single tree. But in truth, it is nothing more than a single branch.","TWN":"你以為自己生活的世界是一棵樹，但其實那只是一根樹枝而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"하지만 너도 알다시피, 나무에선 새로운 가지가 끝없이 자라나지.","JPN":"でもあなたも知っているとおり、木からは新しい枝が絶えず生えてくる。","ENG":"But as you know, trees grow endless new branches.","TWN":"不過你也知道，樹會不斷長出新枝條。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L38_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"그 가지는 세월이 흐르며 역사라는 잔가지를 뻗고, 운명이라는 꽃을 피워내기도 해.","JPN":"その枝は時の流れとともに歴史という小枝を伸ばし、運命という花を咲かせたりもする。","ENG":"Over time, those branches sprout twigs called history and bloom flowers called fate.","TWN":"那些枝條隨著歲月流逝，會長出名為歷史的細枝，也會開出名為命運的花。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"물론 어떤 가지에서든 피어나는 꽃은 똑같아. 가지가 달라도 결국 같은 나무에서 피워낸, 똑같은 꽃이니까.","JPN":"もちろんどの枝も咲く花はみんな同じだよ。枝が違っても、結局は同じ木で咲いた、同じ花だからね。","ENG":"Of course, the flowers that bloom on every branch are the same. Because they all come from the same tree.","TWN":"當然，不管是哪一根枝條上開的花都是一樣的。因為即使枝條不同，它們終究都是從同一棵樹上開出的花。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"똑같은 꽃...?","JPN":"同じ花……？","ENG":"The same flower...?","TWN":"一樣的花……？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L41_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그럼... 저를 닮은 저 사람은 어떻게 되는 거죠?","JPN":"じゃあ……私に似たあの人はどうなるんですか？","ENG":"Then... what will happen to that person who looks like me?","TWN":"那麼……那個長得像我的人會怎麼樣？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"자신이 언니처럼 따르던 소중한 사람을 비극으로 잃고, 비탄에 빠진 채 마왕이 되고 말겠지.","JPN":"自分が姉のように慕っていた大切な人を悲劇によって失い、悲嘆に暮れたまま魔王となってしまうでしょうね。","ENG":"She will lose someone precious to her—someone she followed like an older sister—and fall into despair, becoming a Demon Lord.","TWN":"她會失去像姐姐一樣珍惜的人，在悲痛中成為魔王。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"그것이 그녀의 운명이니까.","JPN":"それが彼女の運命だから。","ENG":"Because that is her fate.","TWN":"那就是她的命運。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"정말 끔찍하네요.","JPN":"本当にぞっとしますね。","ENG":"That's truly horrible.","TWN":"真可怕。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"네가 죽으면 너의 꽃도 지겠지만, 새로운 가지에서 꽃은 다시 피어날 거야.","JPN":"あなたが死ねばあなたの花も散るだろうけど、新しい枝でまた咲くわ。","ENG":"Even if you die, your flower will wither... but it will bloom again on another branch.","TWN":"如果你死了，你的花也會凋謝，但又會在新的枝條上綻放。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"똑같은 모습과 향을 가진, 똑같은 운명으로.","JPN":"同じ姿と同じ香りを持つ、同じ運命を持った花が。","ENG":"With the same appearance and the same scent. The same fate.","TWN":"帶著相同的樣貌與氣息，同樣的命運。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그렇다고 해도... 제가 뭘 할 수 있을까요.","JPN":"そうだとしても……私に何ができるんですか？","ENG":"Even so... what can I possibly do?","TWN":"就算如此……我又能做什麼呢？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"...네 손으로 나뭇가지를 잘라.","JPN":"……枝を切るの。","ENG":"...Cut the branches with your own hands.","TWN":"……用你自己的手剪掉樹枝。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"나뭇가지가 자랄 때마다 꽃이 피어나기 전에 부러뜨리는 거야.","JPN":"枝が生えたら、その都度花が咲く前に折ってしまうの。","ENG":"Each time a branch grows, break it before its flower can bloom.","TWN":"每當長出新枝條，就在還沒開花前折斷它。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"그렇게 모든 나뭇가지를 잘라내고 나면, 운명으로 고통 받는 네 자신도 없어질 거란다.","JPN":"そうやってすべての枝を落としていけば、運命に苦しむあなたも消えるはずよ。","ENG":"If you cut away every branch like that, then the self that suffers under that fate will also disappear.","TWN":"等剪掉所有枝條後，因命運而痛苦的你也會消失。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"다른 세상을 부수기라도 하라는 건가요?","JPN":"別の世界を壊せというのですか？","ENG":"Are you telling me to destroy other worlds?","TWN":"你要我去摧毀其他世界？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그런 엄청난 일을, 아주 간단한 것처럼 말씀하시네요.","JPN":"そんな大それたことを、とても簡単なことのように言うんですね。","ENG":"You say something so enormous as if it were simple.","TWN":"那麼可怕的事，你卻說得這麼輕鬆。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"그럴 수 있는 힘을 줄게.","JPN":"そうできる力をあげる。","ENG":"I will give you the power to do it.","TWN":"我會給你那樣的力量。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":"그 힘을 어떻게 활용할지는 너에게 달렸어.","JPN":"力をどう活用するかはあなた次第だよ。","ENG":"How you use that power will be up to you.","TWN":"至於怎麼使用那股力量，就由你自己決定。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그런 힘을 줄 수 있다면, 당신은 누구죠?","JPN":"そんな力を与えられるなんて、あなたはどういう存在なんですか？","ENG":"If you can grant such power... then who are you?","TWN":"如果你能給我那種力量，你到底是誰？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"요정이나 황금나무보다도 더 대단한 존재인가요?","JPN":"妖精や黄金の木よりもすごい存在なんですか？","ENG":"Are you a being greater than the fairies or the Golden Tree?","TWN":"比精靈或黃金樹更偉大的存在嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_QM","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L14_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"내 이름은 탐미엘.","JPN":"私の名前はタミエル。","ENG":"My name is Tammiel.","TWN":"我的名字是塔米爾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"THAMIEL_NORMAL_NULL_NULL","text":{"KOREA":"첫 번째 가지에서 돋아난...","JPN":"最初の枝から生えた……","ENG":"The one who sprouted from the very first branch...","TWN":"從第一根枝條誕生的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"최초의 마왕이야.","JPN":"最初の魔王だよ。","ENG":"The first Demon Lord.","TWN":"最初的魔王。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"THAMIEL_NORMAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"방금 그건...?","JPN":"今のは……？","ENG":"What was that just now...?","TWN":"剛才那是……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"내가 대체 뭘 본 거지?","JPN":"私が見たのはいったい何？","ENG":"What did I just see?","TWN":"我到底看見了什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"당신이 본 건, 마왕이 되기 전 소녀의 마지막 기억.","JPN":"あなたが見たのは、魔王になる前の少女の最後の記憶。","ENG":"What you saw was the final memory of the girl before she became a Demon Lord.","TWN":"你看到的是那名少女成為魔王前最後的記憶。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"그리고 마왕 타기리온이 당신들의 세계를 멸망 시키려는 이유에요.","JPN":"そして魔王タギリオンがあなたたちの世界を滅亡させようとしている理由です。","ENG":"And the reason why the Demon Lord Thagirion seeks to destroy your world.","TWN":"也是魔王塔基里翁想毀滅你們世界的理由。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};